1	import { quote, createPolicy, claim, type Policy } from "./claim-office.js";
2	
3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type QuoteStep = { op: "quote"; items: Parameters<typeof createPolicy>[0] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Parameters<typeof claim>[1] };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer: Customer; steps: Step[] };
8	type StepResult = { premium: number } | { payout: number; remainingCap: number };
9	
10	async function readStdin(): Promise<string> {
11	  const chunks: Buffer[] = [];
12	  for await (const chunk of process.stdin) {
13	    chunks.push(chunk as Buffer);
14	  }
15	  return Buffer.concat(chunks).toString("utf-8");
16	}
17	
18	function processQuote(
19	  step: QuoteStep,
20	  customer: Customer,
21	  previousQuoteCount: number
22	): { result: StepResult; policy: Policy } {
23	  const customerWithHistory = {
24	    ...customer,
25	    previousContracts: (customer.previousContracts ?? 0) + previousQuoteCount,
26	  };
27	  const premium = quote(customerWithHistory, step.items);
28	  return { result: { premium }, policy: createPolicy(step.items) };
29	}
30	
31	function processClaim(
32	  step: ClaimStep,
33	  policiesByStep: Record<number, Policy>
34	): StepResult {
35	  const policy = policiesByStep[step.policy];
36	  const { payout, remainingCap } = claim(policy, step.incident);
37	  return { payout, remainingCap };
38	}
39	
40	function runScenario(scenario: Scenario): { results: StepResult[] } {
41	  const results: StepResult[] = [];
42	  const policiesByStep: Record<number, Policy> = {};
43	  let previousQuoteCount = 0;
44	  for (let i = 0; i < scenario.steps.length; i++) {
45	    const step = scenario.steps[i];
46	    if (step.op === "quote") {
47	      const { result, policy } = processQuote(step, scenario.customer, previousQuoteCount);
48	      results.push(result);
49	      policiesByStep[i] = policy;
50	      previousQuoteCount++;
51	    } else {
52	      results.push(processClaim(step, policiesByStep));
53	    }
54	  }
55	  return { results };
56	}
57	
58	async function main(): Promise<void> {
59	  const input = await readStdin();
60	  const scenario = JSON.parse(input) as Scenario;
61	  const output = runScenario(scenario);
62	  process.stdout.write(JSON.stringify(output));
63	}
64	
65	main().catch((err) => {
66	  process.stderr.write(String(err?.message ?? err) + "\n");
67	  process.exit(1);
68	});
